class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        int swaps = 0;
        for (int i = 0; i < 2 * n; i += 2) {
            if ((row[i] ^ row[i+1]) == 1) {
                continue;
            }
            int target = row[i] ^ 1;
            int j;
            for (j = i + 1; j < 2 * n; ++j) {
                if (row[j] == target) {
                    break;
                }
            }
            swap(row[i+1], row[j]);
            swaps++;
        }
        return swaps;
    }
};

